#!/usr/bin/env bash
# leaf.sh - Beautiful documentation and landing page generator
# Version: 2.2.0 - Now using myst.sh templating engine
# Generated by hammer.sh

set -euo pipefail

# Get script directory
if command -v dirname >/dev/null 2>&1; then
	SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
else
	# Fallback if dirname is not available
	SCRIPT_DIR="$(cd "${BASH_SOURCE[0]%/*}" && pwd)"
fi
TEMPLATES_DIR="${SCRIPT_DIR}/templates"

# Colors for output
export FORCE_COLOR=${FORCE_COLOR:-}
if [[ -z "$FORCE_COLOR" ]]; then
	if [[ "$FORCE_COLOR" = "1" ]]; then
		export RED='\033[0;31m'
		export GREEN='\033[0;32m'
		export YELLOW='\033[1;33m'
		export BLUE='\033[0;34m'
		export CYAN='\033[0;36m'
		export MAGENTA='\033[0;35m'
		export BOLD='\033[1m'
		export NC='\033[0m'
	else
		export RED=''
		export GREEN=''
		export YELLOW=''
		export BLUE=''
		export CYAN=''
		export MAGENTA=''
		export BOLD=''
		export NC=''
	fi
elif [[ -t 1 ]] && [[ -t 2 ]]; then
	export RED='\033[0;31m'
	export GREEN='\033[0;32m'
	export YELLOW='\033[1;33m'
	export BLUE='\033[0;34m'
	export CYAN='\033[0;36m'
	export MAGENTA='\033[0;35m'
	export BOLD='\033[1m'
	export NC='\033[0m'
else
	export RED=''
	export GREEN=''
	export YELLOW=''
	export BLUE=''
	export CYAN=''
	export MAGENTA=''
	export BOLD=''
	export NC=''
fi

# Default configuration
PROJECT_DIR="${1:-.}"
OUTPUT_DIR="${PROJECT_DIR}/docs"
MODE="docs"
LOGO_PATH=""
BASE_PATH="/"
GITHUB_URL="https://github.com/butter-sh"
PROJECTS_FILE=""
PROJECTS_JSON=""

# Helper functions
log_info() {
	echo -e "${BLUE}ℹ${NC} $1"
}

log_success() {
	echo -e "${GREEN}✓${NC} $1"
}

log_warn() {
	echo -e "${YELLOW}⚠${NC} $1"
}

log_error() {
	echo -e "${RED}✗${NC} $1"
}

log_debug() {
	if [[ "${DEBUG:-0}" == "1" ]]; then
		echo -e "${MAGENTA}🔍${NC} $1"
	fi
}

# Find myst.sh
find_myst() {
	local myst_path=""
	
	# Try .arty/bin/myst first
	if [[ -x "${SCRIPT_DIR}/.arty/bin/myst" ]]; then
		myst_path="${SCRIPT_DIR}/.arty/bin/myst"
	# Try sibling myst directory
	elif [[ -x "${SCRIPT_DIR}/../myst/myst.sh" ]]; then
		myst_path="${SCRIPT_DIR}/../myst/myst.sh"
	# Try system myst
	elif command -v myst &>/dev/null; then
		myst_path="myst"
	else
		log_error "myst.sh not found. Please install it or run 'arty deps' in leaf.sh directory"
		return 1
	fi
	
	echo "$myst_path"
}

# Render template with myst
render_with_myst() {
	local template="$1"
	local output="$2"
	local json_file="$3"
	
	local myst_path=$(find_myst)
	[[ -z "$myst_path" ]] && return 1
	
	log_debug "Using myst: $myst_path"
	log_debug "Template: $template"
	log_debug "Output: $output"
	log_debug "JSON file: $json_file"
	
	# Create output directory
	mkdir -p "$(dirname "$output")"
	
	# Check if template exists
	if [[ ! -f "$template" ]]; then
		log_error "Template not found: $template"
		return 1
	fi
	
	# Check if JSON file exists
	if [[ ! -f "$json_file" ]]; then
		log_error "JSON data file not found: $json_file"
		return 1
	fi
	
	# Render with myst - capture both stdout and stderr
	local myst_output
	local myst_exit_code
	
	if myst_output=$(bash "$myst_path" render \
		-t "$template" \
		-j "$json_file" \
		-p "${TEMPLATES_DIR}/partials" \
		-o "$output" 2>&1); then
		myst_exit_code=0
	else
		myst_exit_code=$?
	fi
	
	# Show myst output only if debug is enabled or if there was an error
	if [[ "${DEBUG:-0}" == "1" ]] || [[ $myst_exit_code -ne 0 ]]; then
		echo "$myst_output" | grep -v "^\[" || true
	fi
	
	if [[ $myst_exit_code -ne 0 ]]; then
		log_error "Myst rendering failed with exit code $myst_exit_code"
		return $myst_exit_code
	fi
	
	# Verify output was created
	if [[ ! -f "$output" ]]; then
		log_error "Myst did not create output file: $output"
		return 1
	fi
	
	return 0
}

# Check dependencies
check_dependencies() {
	local missing_deps=()

	if ! command -v yq &>/dev/null; then
		missing_deps+=("yq")
	fi

	if ! command -v jq &>/dev/null; then
		missing_deps+=("jq")
	fi

	if [ ${#missing_deps[@]} -gt 0 ]; then
		log_error "Missing required dependencies: ${missing_deps[*]}"
		log_info "Install yq: https://github.com/mikefarah/yq#install"
		log_info "Install jq: https://stedolan.github.io/jq/download/"
		return 1
	fi

	# Check for myst
	if ! find_myst >/dev/null 2>&1; then
		log_error "myst.sh not found"
		log_info "Run 'arty deps' in the leaf.sh directory to install dependencies"
		return 1
	fi

	return 0
}

# Show usage
