	cat <<EOF
${CYAN}╔═══════════════════════════════════════════╗${NC}
${CYAN}║                                           ║${NC}
${CYAN}║   🌿 leaf.sh - Documentation Generator   ║${NC}
${CYAN}║                                           ║${NC}
${CYAN}╚═══════════════════════════════════════════╝${NC}

${GREEN}DESCRIPTION:${NC}
    leaf.sh generates beautiful static HTML documentation from arty.sh projects
    and creates stylish landing pages for butter.sh with modern design.
    
    ${CYAN}Now powered by myst.sh templating engine!${NC}

${GREEN}USAGE:${NC}
    ${CYAN}# Generate documentation for arty.sh project${NC}
    leaf.sh [project-dir] [options]
    
    ${CYAN}# Generate butter.sh landing page${NC}
    leaf.sh --landing [options]

${GREEN}OPTIONS:${NC}
    ${YELLOW}--landing${NC}              Generate butter.sh landing page instead of docs
    ${YELLOW}--logo${NC} PATH            Path to logo/icon file
    ${YELLOW}--base-path${NC} PATH       Base path for HTML links (default: /)
    ${YELLOW}--github${NC} URL           GitHub organization URL
    ${YELLOW}--projects${NC} JSON        JSON array of projects for landing page
    ${YELLOW}--projects-file${NC} FILE   JSON file containing projects array
    ${YELLOW}-o, --output${NC} DIR       Output directory (default: docs)
    ${YELLOW}-h, --help${NC}             Show this help message
    ${YELLOW}--version${NC}              Show version information
    ${YELLOW}--debug${NC}                Enable debug output

${GREEN}DEPENDENCIES:${NC}
    • ${YELLOW}yq${NC} - YAML parser (required)
    • ${YELLOW}jq${NC} - JSON processor (required)
    • ${YELLOW}myst.sh${NC} - Templating engine (required)

